    public ulong Status { get; init; }

    public static SetPoolDRevenueAddressOutput FromBytes(ReadOnlySpan<byte> data)
    {
        return new SetPoolDRevenueAddressOutput
        {
            Status = BinaryPrimitives.ReadUInt64LittleEndian(data[0..])
        };
    }
}
